import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";

function EmployeeOffers() {
  const navigate = useNavigate();

  const loggedUser =
    JSON.parse(localStorage.getItem("loggedInUser")) || {};

  const [offers, setOffers] = useState([]);

  useEffect(() => {
    const allOffers =
      JSON.parse(localStorage.getItem("offerLetters")) || [];

    // 🔥 FILTER OFFERS FOR LOGGED-IN EMPLOYEE
    const myOffers = allOffers.filter(
      (offer) => offer.email === loggedUser.email
    );

    setOffers(myOffers);
  }, [loggedUser.email]);

  return (
    <div style={{ marginTop: "25px" }}>
      <h2>My Job Offers</h2>

      {offers.length === 0 ? (
        <p>No offers received yet.</p>
      ) : (
        <table className="designation-table">
          <thead>
            <tr>
              <th>S.No</th>
              <th>Job Title</th>
              <th>Salary</th>
              <th>Joining Date</th>
              <th>Location</th>
              <th>Action</th>
            </tr>
          </thead>

          <tbody>
            {offers.map((offer, index) => (
              <tr key={offer.applicationId}>
                <td>{index + 1}</td>
                <td>{offer.jobTitle}</td>
                <td>₹{offer.salary}</td>
                <td>{offer.joiningDate}</td>
                <td>{offer.location}</td>

                <td>
                  <button
                    onClick={() =>
                      navigate(
                        `/dashboard/recruitment/offer-preview/${offer.applicationId}`
                      )
                    }
                  >
                    View Offer
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      )}
    </div>
  );
}

export default EmployeeOffers;
